Expression:
DIVIDE(
    [Décès WASH (filtrés stabilité)],
    CALCULATE(
        SUM(fact_dashboard_star_fr[population_totale])
    )
) * 100000

VAR AnneRef = [Annee ref KPI]
RETURN COALESCE(
CALCULATE (
SUM ( Fact_KPI_Monde[population_totale] ),
Fact_KPI_Monde[annee] = AnneRef && NOT Fact_KPI_Monde[iso3] IN {"HKG","MAC","TWN"}
),0)

MAXX (
    FILTER (
        ALLSELECTED ( dim_annee_star_fr[annee] ),
        NOT ISBLANK (
            CALCULATE (
                AVERAGE ( Fact_KPI_Monde[acces_eau_potable_pct] )
            )
        )
    ),
    dim_annee_star_fr[annee]
)

MAXX (
    FILTER (
        ALLSELECTED ( dim_annee_star_fr[annee] ),
        NOT ISBLANK (
            CALCULATE (
                AVERAGE ( Fact_KPI_Monde[population_totale] )
            )
        )
        && NOT ISBLANK (
            CALCULATE (
                AVERAGE ( Fact_KPI_Monde[acces_eau_potable_pct] )
            )
        )
    ),
    dim_annee_star_fr[annee]
)

var popRuralePays = 
COALESCE (
    VAR AnneeRef = [Année de référence accès eau KPI]
    RETURN
        CALCULATE (
            SUM ( fact_dashboard_star_fr[population_rurale] ),
            dim_annee_star_fr[annee] = AnneeRef,
            dim_action_star_fr[action_prioritaire] <> "Non classe"
        ),
    0
)
RETURN COALESCE(
if (popRuralePays =0, BLANK(), popRuralePays),0)

COALESCE(
    COUNTROWS(
        FILTER(
            VALUES(dim_pays_star_fr[iso3]),
            CALCULATE(
                AVERAGE(Fact_KPI_Monde[stabilite_politique]),
                KEEPFILTERS(dim_annee_star_fr[annee] = 2016)
            ) < [Seuil stabilité]
        )
    ),
    0
)

COALESCE(
    COUNTROWS(
        FILTER(
            VALUES(dim_pays_star_fr[iso3]),
            CALCULATE(
                AVERAGE(Fact_KPI_Monde[stabilite_politique]),
                KEEPFILTERS(dim_annee_star_fr[annee] = 2018)
            ) < [Seuil stabilité]
        )
    ),
    0
)
